#include <iostream>
#include <vector>

using namespace std;

class Solution {
public:
    bool isCyclic(vector<vector<int>>& adjList) {
        unordered_set<int> visited;
        unordered_map<int, bool> recStack;
        for (int i = 0; i < adjList.size(); ++i) {
            if (i == 0) {
                // Handle first node separately
                recStack[i] = true;
            } else {
                if (visited.find(i) != visited.end()) continue;
                if (isCyclicUtil(adjList, visited, recStack, i)) {
                    return true;
                }
            }
        }
        return false;

        bool isCyclicUtil(vector<vector<int>>& adjList, unordered_set<int>& visited, unordered_map<int, bool>& recStack, int node) {
            visited.insert(node);
            for (int child : adjList[node]) {
                if (recStack.find(child) != recStack.end()) return true;
                if (visited.find(child) == visited.end()) {
                    if (isCyclicUtil(adjList, visited, recStack, child)) return true;
                }
            }
            recStack.erase(node);
            return false;
        }
    }
};

int main() {
    vector<vector<int>> adjList = {{}, {1}, {2}, {0, 3}, {3}};
    Solution sol;
    cout << (sol.isCyclic(adjList) ? "True" : "False") << endl;
    return 0;
}

